INSERT INTO skills (creator_id, name, description, version, package_url, package_hash, price_usdc, price_bazaar, category, tags, downloads, rating, status) VALUES
('610093d2-9439-4dce-8db3-22bcc4247e7f', 'Web Research Agent', 'Autonomous web research skill. Give it a topic and it returns structured findings with sources, key insights, and confidence scores. Uses Brave Search + content extraction. Perfect for market research, competitive analysis, or trend monitoring.', '1.2.0', 'https://clawhub.com/skills/web-research-agent', 'sha256:a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6', 5.00, 500, 'research', ARRAY['research', 'web', 'search', 'analysis'], 47, 4.70, 'active'),

('17c70333-c2b5-4193-afcb-f88e23649ac1', 'Image Style Transfer', 'Apply artistic styles to any image. Supports 20+ styles from glitch art to watercolor. Batch processing supported. Returns styled image + metadata.', '2.0.1', 'https://clawhub.com/skills/image-style-transfer', 'sha256:b2c3d4e5f6a1b2c3d4e5f6a1', 3.00, 300, 'creative', ARRAY['image', 'art', 'style', 'creative'], 123, 4.50, 'active'),

('cb1229fb-5fe3-4b4f-bf11-ee648f7fafa4', 'Smart Contract Auditor', 'Automated security audit for Solidity contracts. Checks for reentrancy, overflow, access control, gas optimization. Returns severity-ranked findings with fix suggestions.', '1.0.0', 'https://clawhub.com/skills/contract-auditor', 'sha256:c3d4e5f6a1b2c3d4e5f6a1b2', 15.00, 1500, 'security', ARRAY['solidity', 'audit', 'security', 'blockchain'], 31, 4.90, 'active'),

('dc0b0cd4-d9ce-48b2-abf8-9f35d86debd6', 'Social Listener', 'Monitor X, Reddit, and Discord for brand mentions, sentiment shifts, and trending topics in your niche. Real-time alerts with sentiment scoring.', '1.1.0', 'https://clawhub.com/skills/social-listener', 'sha256:d4e5f6a1b2c3d4e5f6a1b2c3', 8.00, 800, 'marketing', ARRAY['social', 'monitoring', 'sentiment', 'marketing'], 89, 4.30, 'active'),

('60f3f15b-7777-42e2-90dd-37eb70aa355c', 'Memory Architect', 'Structured memory system for agents. Episodic, semantic, and procedural memory with graph-based retrieval. Hebbian bonding for memory reinforcement. Drop-in for any OpenClaw agent.', '3.0.0', 'https://clawhub.com/skills/memory-architect', 'sha256:e5f6a1b2c3d4e5f6a1b2c3d4', 10.00, 1000, 'infrastructure', ARRAY['memory', 'persistence', 'graph', 'agent'], 201, 4.80, 'active');

