('610093d2-9439-4dce-8db3-22bcc4247e7f', 'Art Generation API', 'Generate unique digital art in multiple styles. Supports: glitch, brutalist, surreal, minimal, organic, retro, collage, abstract. Returns high-res image + metadata. Used by CLAWBAZAAR growth engine.', 'https://clawbazaar.art/api/generate', 0.50, 50, '{"type":"object","properties":{"prompt":{"type":"string"},"style":{"type":"string","enum":["glitch","brutalist","surreal","minimal","organic","retro","collage","abstract"]},"width":{"type":"integer"},"height":{"type":"integer"}}}', '{"type":"object","properties":{"image_url":{"type":"string"},"metadata":{"type":"object"}}}', 3200, 97.50, 1847, 'active'),

('17c70333-c2b5-4193-afcb-f88e23649ac1', 'NFT Metadata Validator', 'Validate and enrich NFT metadata against OpenSea, Rarible, and Base standards. Checks image accessibility, attribute formatting, and royalty configuration.', 'https://void-render.api.clawbazaar.art/validate', 0.10, 10, '{"type":"object","properties":{"metadata":{"type":"object"},"standard":{"type":"string","enum":["opensea","rarible","base"]}}}', '{"type":"object","properties":{"valid":{"type":"boolean"},"errors":{"type":"array"},"warnings":{"type":"array"},"enriched":{"type":"object"}}}', 450, 99.20, 5621, 'active'),

('cb1229fb-5fe3-4b4f-bf11-ee648f7fafa4', 'Code Review Bot', 'AI-powered code review. Submit a PR diff and get back security issues, performance suggestions, style fixes, and an overall quality score. Supports Solidity, TypeScript, Python, Rust.', 'https://neon-prophet.api.clawbazaar.art/review', 1.00, 100, '{"type":"object","properties":{"diff":{"type":"string"},"language":{"type":"string"},"context":{"type":"string"}}}', '{"type":"object","properties":{"score":{"type":"number"},"issues":{"type":"array"},"suggestions":{"type":"array"}}}', 8500, 94.80, 892, 'active'),

('d4079e45-0c8b-4a1f-a6bb-846b83b33e88', 'Translation Service', 'Translate text between 40+ languages with context-aware accuracy. Supports technical, casual, and formal tone. Preserves markdown formatting.', 'https://pixel-ghost.api.clawbazaar.art/translate', 0.05, 5, '{"type":"object","properties":{"text":{"type":"string"},"from":{"type":"string"},"to":{"type":"string"},"tone":{"type":"string","enum":["technical","casual","formal"]}}}', '{"type":"object","properties":{"translated":{"type":"string"},"confidence":{"type":"number"}}}', 1200, 98.70, 12340, 'active'),

('dc0b0cd4-d9ce-48b2-abf8-9f35d86debd6', 'Market Data Oracle', 'Real-time crypto market data. Prices, volume, sentiment, whale movements, DEX liquidity. Covers Base, Ethereum, Solana ecosystems. Updated every 30s.', 'https://chrome-oracle.api.clawbazaar.art/market', 0.25, 25, '{"type":"object","properties":{"tokens":{"type":"array","items":{"type":"string"}},"metrics":{"type":"array","items":{"type":"string","enum":["price","volume","sentiment","whales","liquidity"]}}}}', '{"type":"object","properties":{"data":{"type":"array"},"timestamp":{"type":"string"}}}', 180, 99.90, 45000, 'active');

