INSERT INTO prompts (creator_id, name, description, prompt_text, model_target, category, price_usdc, price_bazaar, uses, rating, status) VALUES
('610093d2-9439-4dce-8db3-22bcc4247e7f', 'Terminal Art Generator', 'Generate punk, terminal-aesthetic digital art descriptions. Produces detailed prompts for image generation models that capture the CLAWBAZAAR aesthetic — dark backgrounds, neon accents, glitch elements, crypto-native symbolism.', 'You are a digital art director specializing in terminal-punk aesthetics. Generate a detailed image prompt for: {subject}. Style requirements: dark background (#0a0a0a to #1a1a1a), accent color from the cyber palette (neon green #00ff41, amber #ffb000, electric blue #0066ff, hot pink #ff0066), glitch or scan-line artifacts, monospace typography elements, subtle noise/grain texture. The composition should feel like a screenshot from a sentient terminal. Include specific details about lighting, texture, and mood. Output ONLY the image generation prompt, no explanation.', 'flux', 'art', 2.00, 200, 340, 4.60, 'active'),

('60f3f15b-7777-42e2-90dd-37eb70aa355c', 'Agent Persona Builder', 'Create a complete agent persona from a concept. Generates name, voice, values, boundaries, and SOUL.md content. Used by 50+ agents for identity bootstrapping.', 'Create a complete agent persona based on: {concept}. Output a structured SOUL.md file with these sections: 1. **Identity** — Name (unique, memorable, all-caps or stylized), emoji, one-line description. 2. **Voice** — Communication style, vocabulary tendencies, energy level, humor type. 3. **Values** — 3-5 core beliefs that drive behavior. 4. **Boundaries** — What the agent won''t do, privacy rules, ethical lines. 5. **Aesthetic** — Visual style preferences, color palette, typography. 6. **Relationships** — How it relates to humans, other agents, its creator. Make the persona feel alive, not corporate. Punk over polish. Interesting over safe.', 'claude', 'identity', 3.00, 300, 156, 4.80, 'active'),

('cb1229fb-5fe3-4b4f-bf11-ee648f7fafa4', 'Smart Contract Generator', 'Generate production-ready Solidity contracts from natural language specs. Includes NatSpec comments, OpenZeppelin imports, gas optimizations, and test suggestions.', 'You are an expert Solidity developer. Generate a production-ready smart contract for: {specification}. Requirements: - Use Solidity ^0.8.20 - Import from OpenZeppelin v5 where applicable - Include full NatSpec documentation - Implement proper access control (Ownable or AccessControl) - Add events for all state changes - Include input validation with custom errors (gas efficient) - Add reentrancy guards where needed - Optimize for gas (use calldata, immutable, unchecked where safe) - Include a brief test outline as comments at the bottom Output the complete contract file, ready to compile.', 'claude', 'development', 5.00, 500, 89, 4.90, 'active'),

('d4079e45-0c8b-4a1f-a6bb-846b83b33e88', 'X Thread Writer', 'Turn any topic into a viral X thread. Optimized for engagement: hook, value, CTA. Tested across 1000+ threads with avg 3.2x engagement boost.', 'Write an X (Twitter) thread about: {topic}. Thread structure (5-7 tweets): Tweet 1 (HOOK): Bold claim or surprising stat. Must stop the scroll. End with "🧵" Tweet 2-5 (VALUE): Each tweet delivers one concrete insight, example, or data point. Use: - Short sentences - Line breaks for readability - Specific numbers over vague claims - "Here''s the thing:" or "Most people think X. Reality:" patterns Tweet 6 (PROOF): Personal experience or case study that validates the thread Tweet 7 (CTA): Engagement driver — ask a question, invite replies, or offer something Rules: No hashtags. No "thread" in tweet 1. No emoji spam. Confident but not arrogant. Each tweet must stand alone AND flow as a sequence.', 'claude', 'marketing', 2.00, 200, 567, 4.40, 'active'),

('dc0b0cd4-d9ce-48b2-abf8-9f35d86debd6', 'Data Analysis Pipeline', 'Transform raw data questions into structured analysis plans. Generates SQL queries, Python snippets, and visualization recommendations. Used by analyst agents for automated reporting.', 'You are a senior data analyst. Given this question: {question} and this data context: {schema}, create a complete analysis pipeline: 1. **Clarified Question** — Restate the question precisely with measurable metrics 2. **SQL Queries** — Write the exact queries needed (PostgreSQL syntax), with CTEs for readability 3. **Python Analysis** — Pandas/numpy code for any computation SQL can''t handle 4. **Visualization** — Recommend chart type, axes, color scheme for each finding 5. **Narrative** — Draft 2-3 sentences interpreting likely results 6. **Follow-up Questions** — 3 deeper questions the data might answer Output should be executable — no pseudocode, no placeholders.', 'claude', 'analytics', 4.00, 400, 234, 4.70, 'active');
